-- =========================
-- DROP + CREATE INFRASTRUCTURE KPI TABLE
-- =========================

DROP TABLE IF EXISTS infrastructure_kpis CASCADE;

CREATE TABLE infrastructure_kpis (
  id SERIAL PRIMARY KEY,
  institution_id INTEGER REFERENCES institutions(id),
  semester VARCHAR(20),
  classroom_occupancy_rate DECIMAL(5,2),
  it_equipment_status_pct DECIMAL(5,2),
  equipment_availability_rate DECIMAL(5,2),
  ongoing_works INTEGER,
  maintenance_requests INTEGER,
  resolved_requests INTEGER,
  lab_availability_rate DECIMAL(5,2),
  library_capacity_used_pct DECIMAL(5,2),
  recorded_at TIMESTAMP DEFAULT NOW()
);

